import json,sys,urllib.request,urllib.error,time,copy
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def call(method,u,data=None,budget=40):
    h={'X-N8N-API-KEY':K}
    if data is not None: h['Content-Type']='application/json'
    t=time.monotonic(); last=None
    while time.monotonic()-t<budget:
        try:
            r=urllib.request.urlopen(urllib.request.Request(B+u,data=data,method=method,headers=h),timeout=15)
            return r.status, r.read()
        except urllib.error.HTTPError as e:
            if e.code in (404,502,503): last=e; time.sleep(3); continue
            return e.code, e.read()
        except Exception as e:
            last=e; time.sleep(3)
    return None, str(last).encode()
